import{_ as e,o as l,c as d,a3 as a}from"./chunks/framework.d0TBG0Rg.js";const x=JSON.parse('{"title":"舞萌 DX 专项","description":"舞萌 DX 查分、查歌、服务器状态监控和成绩同步的用法说明。","frontmatter":{"title":"舞萌 DX 专项","description":"舞萌 DX 查分、查歌、服务器状态监控和成绩同步的用法说明。"},"headers":[],"relativePath":"features/maimai.md","filePath":"features/maimai.md"}'),r={name:"features/maimai.md"};function i(o,t,s,n,c,g){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="舞萌-dx-专项" tabindex="-1">舞萌 DX 专项 <a class="header-anchor" href="#舞萌-dx-专项" aria-label="Permalink to &quot;舞萌 DX 专项&quot;">​</a></h1><blockquote><p>查分、查歌与排队服务。 <br></p></blockquote><div class="mzk-card mzk-card--orange"><h3>🟡 核心查询</h3><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>今日舞萌</code></td><td style="text-align:left;">查看今日运势与推荐曲</td></tr><tr><td style="text-align:left;"><code>b50</code></td><td style="text-align:left;">查询 Best 50 成绩</td></tr><tr><td style="text-align:left;"><code>随个 [难度]</code></td><td style="text-align:left;">随机推歌 (例: <code>随个紫</code>)</td></tr><tr><td style="text-align:left;"><code>查歌 [关键词]</code></td><td style="text-align:left;">查询曲目详细信息</td></tr><tr><td style="text-align:left;"><code>定数查歌 [范围]</code></td><td style="text-align:left;">例: <code>定数查歌 13.5 13.9</code></td></tr></tbody></table></div></div><div class="mzk-card mzk-card--green"><h3>🟢 牌子与进度</h3><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>[牌子]进度</code></td><td style="text-align:left;">例: <code>霸者进度</code> / <code>舞舞进度</code></td></tr><tr><td style="text-align:left;"><code>[等级]进度</code></td><td style="text-align:left;">例: <code>13+进度</code></td></tr><tr><td style="text-align:left;"><code>完成表 [等级]</code></td><td style="text-align:left;">生成等级完成度图片</td></tr><tr><td style="text-align:left;"><code>分数线 [曲ID]</code></td><td style="text-align:left;">查询各达成率所需分数</td></tr></tbody></table></div></div><div class="mzk-card mzk-card--blue"><h3>🔵 查询与娱乐</h3><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>是什么歌</code></td><td style="text-align:left;">查询别名对应的歌曲</td></tr><tr><td style="text-align:left;"><code>[牌名/难度]是什么谱</code></td><td style="text-align:left;">查询指定谱面信息</td></tr><tr><td style="text-align:left;"><code>查[别名] 谱面[难度]</code></td><td style="text-align:left;">精确查询特定歌曲难度谱面</td></tr><tr><td style="text-align:left;"><code>添加别名 [ID] [名]</code></td><td style="text-align:left;">提交新的歌曲别名</td></tr><tr><td style="text-align:left;"><code>mai猜歌</code></td><td style="text-align:left;">开启猜歌小游戏</td></tr></tbody></table></div></div><div class="mzk-card mzk-card--purple"><h3>🖥️ 舞萌服务器状态</h3><h4>🔗 查看服务器状态 (无需私钥即可查询)</h4><p>发送 <code>/net</code> 、 <code>网咋样</code> 或 <code>炸了吗</code></p><h4>🔗 手动上报 (需要 Client ID + 私钥才可上报)</h4><ul><li><code>/report 断网</code></li><li><code>/report 小黑屋</code></li><li><code>/report 被发票</code></li><li><code>/report 罚站 300</code></li><li><code>/report help</code></li></ul><h4>🔗 自动监听 (群聊)</h4><p>插件会自动识别群聊中的以下说法并上报，无需手动触发：</p><p><strong>异常触发 (主语+动词组合)</strong></p><ul><li><strong>主语</strong>：华立、SEGA、服务器、机台、NET等</li><li><strong>动词</strong>：炸、挂、死、坏、崩等</li><li><strong>示例</strong>：「服务器又炸了」「SEGA挂了」「机台灰网」「游客了」「20min了」</li></ul><strong>正常触发</strong><ul><li><strong>示例</strong>：「服务器好了」「华立稳了」「绿网了」</li></ul><strong>冯氏指数</strong><ul><li><strong>起飞 (异常)</strong>：「华立冯飞了」「SEGA老冯起飞」</li><li><strong>返航 (正常)</strong>：「华立冯返航了」「SEGA老冯落地」</li></ul></div><div class="mzk-card mzk-card--orange"><h3>🟠 骚话模式 (娱乐)</h3><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>xxmai什么</code></td><td style="text-align:left;">例: <code>柚子mai什么</code></td></tr><tr><td style="text-align:left;"><code>我要在 [难度] 上 [分]</code></td><td style="text-align:left;">立 flag</td></tr><tr><td style="text-align:left;"><code>今天mai出勤打什么</code></td><td style="text-align:left;">随机推荐</td></tr></tbody></table></div></div><div class="mzk-card mzk-card--red"><h3>✨ 舞萌DX 成绩同步助手 ✨</h3><div class="mzk-alert"><strong>⚠️ 维护时间: 每日 00:00-11:00 暂停服务</strong><br><strong>⚠️ 注意:</strong> 落雪绑定已升级为 OAuth 2.0 链接授权，旧版 token 已失效，现支持链接授权，更加方便！ </div><h4>📜 免责声明 (使用前必读)</h4><p>发送任意指令可查看协议链接。必须同意后方可使用本功能。</p><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>同意Mizuki免责声明</code></td><td style="text-align:left;">同意用户协议</td></tr><tr><td style="text-align:left;"><code>拒绝Mizuki免责声明</code></td><td style="text-align:left;">拒绝用户协议</td></tr><tr><td style="text-align:left;"><code>撤回Mizuki免责声明同意</code></td><td style="text-align:left;">撤回之前的授权同意</td></tr></tbody></table></div><h4>🔑 第一步：设置类型</h4><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>设置类型 1</code></td><td style="text-align:left;"><strong>类型一</strong>：仅上传成绩到查分器后立即返回。</td></tr><tr><td style="text-align:left;"><code>设置类型 2</code></td><td style="text-align:left;"><strong>类型二</strong>：上传成绩后，等待70秒并自动登出 (会上传占位曲)。</td></tr></tbody></table></div><h4>🔑 第二步：绑定账号</h4><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>绑定水鱼 [Token]</code></td><td style="text-align:left;">🐟 绑定水鱼查分器</td></tr><tr><td style="text-align:left;"><code>绑定落雪</code></td><td style="text-align:left;">❄️ 获取落雪认证链接</td></tr><tr><td style="text-align:left;"><code>落雪确认 [授权码]</code></td><td style="text-align:left;">✅ 确认并完成落雪绑定</td></tr></tbody></table></div><h4>📊 第三步：同步成绩与查询</h4><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>上传成绩</code></td><td style="text-align:left;">开始同步 (发送指令后，再发送二维码文本)</td></tr><tr><td style="text-align:left;"><code>预览mai</code></td><td style="text-align:left;">查看用户游戏账号的基本信息 (发送指令后，再发送二维码文本)</td></tr><tr><td style="text-align:left;"><code>取消</code></td><td style="text-align:left;">取消当前操作，退出上传流程</td></tr></tbody></table></div><h4>🚦 队列系统与管理</h4><p> • 队列最多容纳 10 人，同时只能处理 1 个用户。<br> • 类型一用户结束后，立即开始处理下一个；<br> • 类型二用户需等待其登出后 10 秒，下一个用户才开始。 </p><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>队列状态</code></td><td style="text-align:left;">查看当前队列排队人数</td></tr><tr><td style="text-align:left;"><code>查看绑定</code></td><td style="text-align:left;">查看当前绑定状态和类型</td></tr><tr><td style="text-align:left;"><code>登出</code></td><td style="text-align:left;">强制清理异常登录状态</td></tr><tr><td style="text-align:left;"><code>设置类型</code></td><td style="text-align:left;">重新设置用户类型 (1或2)</td></tr></tbody></table></div></div>',8)])])}const f=e(r,[["render",i]]);export{x as __pageData,f as default};
